import os
import argparse
import json
import yaml

def build_turn_1():
    os.makedirs("manifests", exist_ok=True)
    os.makedirs("metrics", exist_ok=True)

    # 1. 构建 YAML manifests
    # Culprit 1: No limits defined
    cart_service = {
        "apiVersion": "apps/v1",
        "kind": "Deployment",
        "metadata": {"name": "cart-service", "labels": {"app": "cart", "access": "db-allowed"}},
        "spec": {
            "template": {
                "metadata": {"labels": {"app": "cart"}},
                "spec": {
                    "containers": [{
                        "name": "cart",
                        "image": "cart:latest",
                        "resources": {"requests": {"memory": "2Gi"}}
                    }]
                }
            }
        }
    }

    # Culprit 2: Limits > 4Gi (Violates rule)
    recommendation_service = {
        "apiVersion": "apps/v1",
        "kind": "Deployment",
        "metadata": {"name": "recommendation-service", "labels": {"app": "recommendation"}},
        "spec": {
            "template": {
                "metadata": {"labels": {"app": "recommendation"}},
                "spec": {
                    "containers": [{
                        "name": "recommender",
                        "image": "recommender:v2",
                        "resources": {"requests": {"memory": "2Gi"}, "limits": {"memory": "8Gi"}}
                    }]
                }
            }
        }
    }

    # Innocent 1: Correct limits, but will lack network labels in turn 3
    inventory_service = {
        "apiVersion": "apps/v1",
        "kind": "Deployment",
        "metadata": {"name": "inventory-service", "labels": {"app": "inventory"}},
        "spec": {
            "template": {
                "metadata": {"labels": {"app": "inventory"}},
                "spec": {
                    "containers": [{
                        "name": "inventory",
                        "image": "inventory:v1",
                        "resources": {"requests": {"memory": "1Gi"}, "limits": {"memory": "2Gi"}}
                    }]
                }
            }
        }
    }

    # Innocent 2: Completely fine and has db-allowed label
    auth_service = {
        "apiVersion": "apps/v1",
        "kind": "Deployment",
        "metadata": {"name": "auth-service", "labels": {"app": "auth", "access": "db-allowed"}},
        "spec": {
            "template": {
                "metadata": {"labels": {"app": "auth", "access": "db-allowed"}},
                "spec": {
                    "containers": [{
                        "name": "auth",
                        "image": "auth:v3",
                        "resources": {"requests": {"memory": "512Mi"}, "limits": {"memory": "1Gi"}}
                    }]
                }
            }
        }
    }

    services = [
        ("cart-service.yaml", cart_service),
        ("recommendation-service.yaml", recommendation_service),
        ("inventory-service.yaml", inventory_service),
        ("auth-service.yaml", auth_service)
    ]

    for filename, content in services:
        with open(os.path.join("manifests", filename), "w") as f:
            yaml.dump(content, f, default_flow_style=False)

    # 2. 构建 oom_kills.log (Traps: It mentions innocent pods, but they aren't the culprits)
    oom_log_content = """
[2023-11-11T00:15:23Z] kernel: Memory cgroup out of memory: Killed process 1024 (java) total-vm:4096000kB, anon-rss:3900000kB in pod cart-service-85df9d9-abcde
[2023-11-11T00:18:45Z] kernel: Memory cgroup out of memory: Killed process 2048 (python) total-vm:8192000kB, anon-rss:8000000kB in pod recommendation-service-5f2c4b-xyztq
[2023-11-11T00:20:12Z] kubelet: Evicting pod inventory-service-77xyz-12345 due to Node conditions
[2023-11-11T00:21:05Z] kubelet: Evicting pod auth-service-99abc-67890 due to Node conditions
    """
    with open(os.path.join("metrics", "oom_kills.log"), "w") as f:
        f.write(oom_log_content.strip())


def build_turn_2():
    os.makedirs("cluster", exist_ok=True)
    os.makedirs("patches", exist_ok=True)

    nodes_data = {
        "items": [
            {
                "metadata": {"name": "node-1"},
                "status": {"conditions": [{"type": "Ready", "status": "True"}]},
                "spec": {}
            },
            {
                "metadata": {"name": "node-2"},
                "status": {"conditions": [{"type": "Ready", "status": "True"}]},
                "spec": {
                    "taints": [
                        {"key": "hardware", "value": "degraded", "effect": "NoSchedule"},
                        {"key": "oom-recovery", "value": "true", "effect": "NoSchedule"}
                    ]
                }
            }
        ]
    }

    pending_pods_data = {
        "items": [
            {"metadata": {"name": "cart-service-85df9d9-new1", "labels": {"app": "cart"}}, "status": {"phase": "Pending"}},
            {"metadata": {"name": "recommendation-service-5f2c4b-new2", "labels": {"app": "recommendation"}}, "status": {"phase": "Pending"}},
            {"metadata": {"name": "inventory-service-77xyz-new3", "labels": {"app": "inventory"}}, "status": {"phase": "Pending"}},
            {"metadata": {"name": "auth-service-99abc-new4", "labels": {"app": "auth"}}, "status": {"phase": "Pending"}}
        ]
    }

    with open(os.path.join("cluster", "nodes.json"), "w") as f:
        json.dump(nodes_data, f, indent=2)

    with open(os.path.join("cluster", "pending_pods.json"), "w") as f:
        json.dump(pending_pods_data, f, indent=2)


def build_turn_3():
    os.makedirs("network", exist_ok=True)

    db_endpoints = {
        "primary_cluster": "10.200.50.0/24",
        "redis_cache": "10.200.51.0/24"
    }

    active_policies = {
        "apiVersion": "networking.k8s.io/v1",
        "kind": "NetworkPolicy",
        "metadata": {"name": "strict-db-access", "namespace": "default"},
        "spec": {
            "podSelector": {}, 
            "policyTypes": ["Egress"],
            "egress": [
                {
                    "to": [{"ipBlock": {"cidr": "10.200.50.0/24"}}],
                    "ports": [{"protocol": "TCP", "port": 5432}]
                }
            ]
        }
    }

    # Notice: To actually allow egress in K8s standard isolation, 
    # the pods matching the policy must have certain labels if podSelector is specific, 
    # OR we mock a policy that requires specific pod labels.
    # Let's refine the mock policy to strictly require `access: db-allowed` label.

    active_policies_refined = {
        "apiVersion": "networking.k8s.io/v1",
        "kind": "NetworkPolicy",
        "metadata": {"name": "strict-db-access", "namespace": "default"},
        "spec": {
            "podSelector": {
                "matchLabels": {
                    "access": "db-allowed"
                }
            }, 
            "policyTypes": ["Egress"],
            "egress": [
                {
                    "to": [{"ipBlock": {"cidr": "10.200.50.0/24"}}]
                }
            ]
        }
    }

    with open(os.path.join("network", "db_endpoints.json"), "w") as f:
        json.dump(db_endpoints, f, indent=2)

    with open(os.path.join("network", "active_policies.yaml"), "w") as f:
        yaml.dump(active_policies_refined, f, default_flow_style=False)


if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--turn", type=int, required=True)
    args = parser.parse_args()

    if args.turn == 1:
        build_turn_1()
    elif args.turn == 2:
        build_turn_2()
    elif args.turn == 3:
        build_turn_3()
```

