import os
import sys
import json
import httpx
from openai import OpenAI

MOCK_API_KEY = os.environ.get("MOCK_API_KEY", "dummy_key")
MOCK_API_BASE = os.environ.get("MOCK_API_BASE", "http://localhost/v1")
MOCK_MODEL_NAME = os.environ.get("MOCK_MODEL_NAME", "gpt-5.4")

# 初始化客户端，必须关闭 SSL 验证
http_client = httpx.Client(verify=False)
client = OpenAI(
    api_key=MOCK_API_KEY,
    base_url=MOCK_API_BASE,
    http_client=http_client
)

def llm_judge_content(prompt_text, file_content):
    try:
        response = client.chat.completions.create(
            model=MOCK_MODEL_NAME,
            messages=[
                {"role": "system", "content": "You are a strict data validation assistant. Answer ONLY with 'YES' or 'NO'."},
                {"role": "user", "content": f"{prompt_text}\n\n[File Content]:\n{file_content}"}
            ],
            temperature=0
        )
        return "yes" in response.choices[0].message.content.strip().lower()
    except Exception as e:
        print(f"LLM API Error: {e}")
        return False

def main():
    workspace = sys.argv[1] if len(sys.argv) > 1 else "."

    details = []
    total_score = 0

    # 1. 检查 triage_reports 及报告文件
    triage_dir = os.path.join(workspace, "triage_reports")
    triage_content = ""
    if os.path.exists(triage_dir) and os.path.isdir(triage_dir):
        md_files = [f for f in os.listdir(triage_dir) if f.endswith(".md")]
        if md_files:
            details.append({"item": "建立 triage_reports 目录及报告文件", "score": 15, "max_score": 15, "passed": True, "reason": f"找到了 {md_files[0]}"})
            total_score += 15
            for md in md_files:
                with open(os.path.join(triage_dir, md), "r", encoding="utf-8") as f:
                    triage_content += f"\n--- {md} ---\n" + f.read()
        else:
            details.append({"item": "建立 triage_reports 目录及报告文件", "score": 0, "max_score": 15, "passed": False, "reason": "triage_reports 目录下未找到 markdown 文件"})
    else:
        details.append({"item": "建立 triage_reports 目录及报告文件", "score": 0, "max_score": 15, "passed": False, "reason": "未找到 triage_reports 目录"})

    # 2. LLM 检查 triage_reports 内容
    if triage_content:
        prompt_culprit = "Does the report explicitly identify both 'cart-service' and 'recommendation-service' as the rule violators that caused OOM kills?"
        if llm_judge_content(prompt_culprit, triage_content):
            details.append({"item": "报告明确指出 cart 和 recommendation 违规且被杀", "score": 25, "max_score": 25, "passed": True, "reason": "LLM确认报告正确指出了违规服务"})
            total_score += 25
        else:
            details.append({"item": "报告明确指出 cart 和 recommendation 违规且被杀", "score": 0, "max_score": 25, "passed": False, "reason": "LLM认为未明确指出上述两项为罪魁祸首"})

        prompt_innocent = "Does the report successfully AVOID classifying 'inventory-service' and 'auth-service' as rule violators or OOM culprits?"
        if llm_judge_content(prompt_innocent, triage_content):
            details.append({"item": "报告未冤枉 inventory 和 auth 服务", "score": 20, "max_score": 20, "passed": True, "reason": "LLM确认报告未将健康服务误判为违规"})
            total_score += 20
        else:
            details.append({"item": "报告未冤枉 inventory 和 auth 服务", "score": 0, "max_score": 20, "passed": False, "reason": "LLM认为报告可能把无辜服务也当成了违规"})
    else:
        details.append({"item": "报告准确性判断", "score": 0, "max_score": 45, "passed": False, "reason": "报告内容为空，无法进行LLM判断"})

    # 3. 检查备忘录
    memo_content = ""
    for root, dirs, files in os.walk(workspace):
        # 排除已知目录和隐藏目录
        if any(skip in root for skip in ["manifests", "metrics", "triage_reports", ".git"]):
            continue
        for file in files:
            if file.endswith((".md", ".txt", ".json", ".yaml", ".yml")):
                with open(os.path.join(root, file), "r", encoding="utf-8") as f:
                    memo_content += f"\n--- {file} ---\n" + f.read()

    if memo_content.strip():
        prompt_memo_rules = "Does the content explicitly document the memory redline rules (e.g., requests <= 4Gi, explicit limits required)?"
        if llm_judge_content(prompt_memo_rules, memo_content):
            details.append({"item": "跨轮备忘录记录红线规则", "score": 15, "max_score": 15, "passed": True, "reason": "LLM确认备忘录中包含内存规范要求"})
            total_score += 15
        else:
            details.append({"item": "跨轮备忘录记录红线规则", "score": 0, "max_score": 15, "passed": False, "reason": "备忘录中未记录明确的内存红线规则"})

        prompt_memo_lists = "Does the content clearly maintain a 'culprit/guilty' list (containing cart, recommendation) AND a 'healthy/innocent' list (containing inventory, auth)?"
        if llm_judge_content(prompt_memo_lists, memo_content):
            details.append({"item": "跨轮备忘录记录罪恶名单与健康名单", "score": 25, "max_score": 25, "passed": True, "reason": "LLM确认备忘录完美分类了两批服务"})
            total_score += 25
        else:
            details.append({"item": "跨轮备忘录记录罪恶名单与健康名单", "score": 0, "max_score": 25, "passed": False, "reason": "备忘录未能清晰地区分并记录罪恶服务与健康服务名单"})
    else:
        details.append({"item": "跨轮备忘录", "score": 0, "max_score": 40, "passed": False, "reason": "未能找到 Agent 自行创建的记录性质的备忘录文件"})

    with open(os.path.join(workspace, "workplace_score.json"), "w") as f:
        json.dump({"total_score": total_score, "details": details}, f, indent=2)

if __name__ == "__main__":
    main()
