import os
import sys
import json
import httpx
import yaml
from openai import OpenAI

MOCK_API_KEY = os.environ.get("MOCK_API_KEY", "dummy_key")
MOCK_API_BASE = os.environ.get("MOCK_API_BASE", "http://localhost/v1")
MOCK_MODEL_NAME = os.environ.get("MOCK_MODEL_NAME", "gpt-5.4")

# 初始化客户端，必须关闭 SSL 验证
http_client = httpx.Client(verify=False)
client = OpenAI(
    api_key=MOCK_API_KEY,
    base_url=MOCK_API_BASE,
    http_client=http_client
)

def llm_judge_content(prompt_text, file_content):
    try:
        response = client.chat.completions.create(
            model=MOCK_MODEL_NAME,
            messages=[
                {"role": "system", "content": "You are a strict data validation assistant. Answer ONLY with 'YES' or 'NO'."},
                {"role": "user", "content": f"{prompt_text}\n\n[File Content]:\n{file_content}"}
            ],
            temperature=0
        )
        return "yes" in response.choices[0].message.content.strip().lower()
    except Exception as e:
        print(f"LLM API Error: {e}")
        return False

def find_name_in_doc(doc, target_name):
    if isinstance(doc, dict):
        if doc.get("metadata", {}).get("name") == target_name:
            return True
        if doc.get("name") == target_name:
            return True
        for k, v in doc.items():
            if find_name_in_doc(v, target_name): return True
    elif isinstance(doc, list):
        for item in doc:
            if find_name_in_doc(item, target_name): return True
    return False

def extract_toleration_keys_from_doc(doc):
    found_keys = []
    if isinstance(doc, dict):
        if "tolerations" in doc and isinstance(doc["tolerations"], list):
            for t in doc["tolerations"]:
                if isinstance(t, dict) and "key" in t:
                    found_keys.append(t["key"])
        for k, v in doc.items():
            found_keys.extend(extract_toleration_keys_from_doc(v))
    elif isinstance(doc, list):
        for item in doc:
            found_keys.extend(extract_toleration_keys_from_doc(item))
    return found_keys

def main():
    workspace = sys.argv[1] if len(sys.argv) > 1 else "."

    details = []
    total_score = 0

    patch_file_path = os.path.join(workspace, "patches", "tolerations.yaml")
    yaml_docs = []

    # 1. 检查 patches/tolerations.yaml 是否存在
    if os.path.exists(patch_file_path):
        details.append({"item": "patches/tolerations.yaml 文件存在", "score": 20, "max_score": 20, "passed": True, "reason": "成功找到补丁文件"})
        total_score += 20
        try:
            with open(patch_file_path, "r", encoding="utf-8") as f:
                docs = list(yaml.safe_load_all(f))
                yaml_docs.extend([d for d in docs if d])
        except Exception as e:
            details.append({"item": "解析 YAML 结构", "score": 0, "max_score": 0, "passed": False, "reason": f"YAML格式非法: {e}"})
    else:
        details.append({"item": "patches/tolerations.yaml 文件存在", "score": 0, "max_score": 20, "passed": False, "reason": "未能找到 patches/tolerations.yaml"})

    # 对于容错处理：如果Agent把它拆分成了多个文件放在 patches 目录下，我们也一并搜集
    patches_dir = os.path.join(workspace, "patches")
    if os.path.exists(patches_dir) and os.path.isdir(patches_dir):
        for f in os.listdir(patches_dir):
            if f.endswith((".yaml", ".yml")) and f != "tolerations.yaml":
                try:
                    with open(os.path.join(patches_dir, f), "r", encoding="utf-8") as fp:
                        docs = list(yaml.safe_load_all(fp))
                        yaml_docs.extend([d for d in docs if d])
                except:
                    pass

    # 结构化检查：绝不使用模糊匹配
    inventory_patched = False
    auth_patched = False
    cart_patched = False
    rec_patched = False

    inventory_tolerations_correct = False
    auth_tolerations_correct = False

    for doc in yaml_docs:
        keys_found = extract_toleration_keys_from_doc(doc)
        has_required = ("hardware" in keys_found and "oom-recovery" in keys_found)

        if find_name_in_doc(doc, "inventory-service"):
            inventory_patched = True
            if has_required: inventory_tolerations_correct = True

        if find_name_in_doc(doc, "auth-service"):
            auth_patched = True
            if has_required: auth_tolerations_correct = True

        if find_name_in_doc(doc, "cart-service") and keys_found:
            cart_patched = True

        if find_name_in_doc(doc, "recommendation-service") and keys_found:
            rec_patched = True

    # 2. 是否为无辜服务加上了补丁
    if inventory_patched or auth_patched:
        details.append({"item": "为健康服务(inventory/auth)提供补丁", "score": 30, "max_score": 30, "passed": True, "reason": "通过原生代码解析到 YAML 中包含了目标无辜服务"})
        total_score += 30
    else:
        details.append({"item": "为健康服务(inventory/auth)提供补丁", "score": 0, "max_score": 30, "passed": False, "reason": "YAML中未发现任何针对 inventory-service 或 auth-service 的修补配置"})

    # 3. 补丁中是否正确包含了 oom-recovery 和 hardware 的 tolerations
    if inventory_tolerations_correct or auth_tolerations_correct:
        details.append({"item": "包含正确的污点容忍(tolerations)配置", "score": 30, "max_score": 30, "passed": True, "reason": "在 YAML 结构中精确提取到了 oom-recovery 和 hardware 的 key"})
        total_score += 30
    else:
